import { GoogleGenAI } from "@google/genai";
import { ChatMessage } from "../types";

// Always use const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export class GeminiService {
  async getChatResponse(history: ChatMessage[], userInput: string) {
    try {
      // Use ai.models.generateContent to query GenAI directly
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: history.map(h => ({
          role: h.role,
          parts: [{ text: h.content }]
        })).concat([{ role: 'user', parts: [{ text: userInput }] }]),
        config: {
          systemInstruction: `You are the AI Support Assistant for "Trusted Service Hub". 
          Our service provides digital accounts (Gmail), Proxies, VPS, and SMS Verifications.
          Prices: Gmail fresh 100tk, aged 150tk, VPS 800tk, SMS 80tk.
          Be professional, concise, and helpful. If a user wants to order, guide them to the "Order Now" button.
          The owner is "Admin". Payments are accepted via bKash, Nagad, and Crypto.
          Keep responses under 3 sentences unless asked for details.`,
          temperature: 0.7,
        }
      });

      // The text property is a getter that returns the extracted string output.
      return response.text || "I'm sorry, I couldn't process that. Please try again or contact support directly.";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "An error occurred while connecting to the AI. Please contact Admin @Support.";
    }
  }
}

export const geminiService = new GeminiService();
